1	export type QuoteContext = {
2	  yearsWithMHPCO: number;
3	  isFollowUp: boolean;
4	};
5	
6	const POLICY_FEE = 5;
7	
8	const BASE_PREMIUM: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	  rune: 25,
14	  moonstone: 25,
15	};
16	
17	const BLOCK_SIZE = 3;
18	const BLOCK_PRICE = 60;
19	
20	const COMPONENT_TYPES = ["rune", "moonstone"];
21	
22	const CURSE_SURCHARGE_RATE = 0.5;
23	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
24	const HIGH_ENCHANTMENT_THRESHOLD = 5;
25	
26	const isComponent = (item: { type: string }): boolean =>
27	  COMPONENT_TYPES.includes(item.type);
28	
29	const basePremiumFor = (item: { type: string }): number => BASE_PREMIUM[item.type];
30	
31	const itemPremium = (item: { type: string; cursed?: boolean; enchantment?: number }): number => {
32	  const base = basePremiumFor(item);
33	  const curseSurcharge = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
34	  const isHighEnchantment = item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD;
35	  const highEnchantmentSurcharge = isHighEnchantment ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0;
36	  return base + curseSurcharge + highEnchantmentSurcharge;
37	};
38	
39	const componentGroupPremium = (type: string, count: number): number =>
40	  count === BLOCK_SIZE ? BLOCK_PRICE : count * BASE_PREMIUM[type];
41	
42	export function quote(items: { type: string; cursed?: boolean; enchantment?: number }[], context: QuoteContext): number {
43	  const componentBasePremium = COMPONENT_TYPES.reduce((sum, type) => {
44	    const count = items.filter((item) => item.type === type).length;
45	    return sum + componentGroupPremium(type, count);
46	  }, 0);
47	
48	  const mainItemsPremium = items
49	    .filter((item) => !isComponent(item))
50	    .reduce((sum, item) => sum + itemPremium(item), 0);
51	
52	  return mainItemsPremium + componentBasePremium + POLICY_FEE;
53	}
54	
55	export function claim(): unknown {
56	  return undefined;
57	}
